import React, { useState } from "react";
import axios from "axios";

const API_URL = "http://127.0.0.1:5000";

function MisinformationChecker() {
  const [text, setText] = useState("");
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const handleClear = () => {
    setText("");
    setResult(null);
    setError("");
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (text.length < 20) {
      setError("Please enter at least 20 characters for analysis.");
      return;
    }
    setIsLoading(true);
    setError("");
    try {
      const response = await axios.post(`${API_URL}/predict/misinformation`, {
        text,
      });
      setResult(response.data);
    } catch (err) {
      setError("API Error. Please check your Gemini API key in the backend.");
    } finally {
      setIsLoading(false);
    }
  };

  const getVerdictClass = (verdict = "") => {
    const upperVerdict = verdict.toUpperCase();
    if (upperVerdict.includes("FAKE")) return "result-deepfake";
    if (upperVerdict.includes("MISLEADING")) return "result-misleading"; // Add this class to CSS if you want a third color
    if (upperVerdict.includes("REAL")) return "result-real";
    return "";
  };

  return (
    <div className="detector-container">
      <h2>📰 Misinformation Checker</h2>
      <form
        onSubmit={handleSubmit}
        style={{
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          gap: "1.5rem",
        }}
      >
        <textarea
          className="text-input-area"
          rows="10"
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Paste a news article or text here..."
        />
        <div className="button-group">
          <button
            type="submit"
            className="btn"
            disabled={isLoading || text.length < 20}
          >
            {isLoading ? "Analyzing..." : "Check Text"}
          </button>
          {text && (
            <button
              type="button"
              className="btn btn-clear"
              onClick={handleClear}
            >
              Clear
            </button>
          )}
        </div>
      </form>

      {isLoading && (
        <div className="spinner-container">
          <div className="spinner"></div>
        </div>
      )}
      {error && (
        <p style={{ color: "var(--danger-color)", textAlign: "center" }}>
          {error}
        </p>
      )}

      {result && (
        <div className={`result-card ${getVerdictClass(result.verdict)}`}>
          <h4>VERDICT: {result.verdict || "UNKNOWN"}</h4>
          <p>Confidence: **{(result.confidence_score * 100).toFixed(2)}%**</p>
          <hr
            style={{
              border: "none",
              borderTop: "1px solid var(--primary-accent)",
            }}
          />
          <p style={{ textAlign: "left" }}>
            <strong>Summary:</strong> {result.summary || "N/A"}
          </p>
        </div>
      )}
    </div>
  );
}

export default MisinformationChecker;
